use crate::{Bar, CandleStore, Series, RcSeries};
use crate::NodeCache;
use crate::{rc_into_owned, nan_to_none};
use std::rc::Rc;
use std::collections::HashMap;
use crate::IndicatorOutput;
use crate::{output_at, output_at_vec};
use crate::IndicatorArena;
use crate::indicators::atr::{atr_node, atr_store, latest_atr, latest_atr_store, true_range_store};

pub fn supertrend(    bars: &[Bar],    period: usize,    multiplier: f64,    nodes: &mut NodeCache,) -> Vec<IndicatorOutput> {    let atr = atr_node(bars, period, nodes);    let mut values = vec![f64::NAN; bars.len()];    let mut upper_band = vec![f64::NAN; bars.len()];    let mut lower_band = vec![f64::NAN; bars.len()];    let mut trend = vec![f64::NAN; bars.len()];    if period == 0 || bars.len() <= period {        return supertrend_outputs(values, upper_band, lower_band, trend);    }    for index in period..bars.len() {        let atr_value = atr[index]; if atr_value.is_nan() {            continue;        };        let hl2 = (bars[index].high + bars[index].low) / 2.0;        let basic_upper = hl2 + multiplier * atr_value;        let basic_lower = hl2 - multiplier * atr_value;        let previous_close = bars[index - 1].close;        let current_upper = if index == period {            basic_upper        } else {            let previous_upper = { let __v = upper_band[index - 1]; if __v.is_nan() { basic_upper } else { __v } };            if basic_upper < previous_upper || previous_close > previous_upper {                basic_upper            } else {                previous_upper            }        };        let current_lower = if index == period {            basic_lower        } else {            let previous_lower = { let __v = lower_band[index - 1]; if __v.is_nan() { basic_lower } else { __v } };            if basic_lower > previous_lower || previous_close < previous_lower {                basic_lower            } else {                previous_lower            }        };        upper_band[index] = current_upper;        lower_band[index] = current_lower;        let current_trend = if index == period {            if bars[index].close >= hl2 {                1.0            } else {                -1.0            }        } else {            let previous_trend = { let __v = trend[index - 1]; if __v.is_nan() { 1.0 } else { __v } };            if previous_trend < 0.0 {                if bars[index].close > current_upper {                    1.0                } else {                    -1.0                }            } else if bars[index].close < current_lower {                -1.0            } else {                1.0            }        };        trend[index] = current_trend;        values[index] = if current_trend < 0.0 { current_upper } else { current_lower };    }    nodes.insert(format!("supertrend:{period}:{multiplier}"), Rc::new(values.clone()));    supertrend_outputs(values, upper_band, lower_band, trend)}
pub fn supertrend_store(    store: &CandleStore,    period: usize,    multiplier: f64,    nodes: &mut NodeCache,) -> Vec<IndicatorOutput> {    let atr = rc_into_owned(atr_store(store, period, nodes));    let mut values = vec![f64::NAN; store.len()];    let mut upper_band = vec![f64::NAN; store.len()];    let mut lower_band = vec![f64::NAN; store.len()];    let mut trend = vec![f64::NAN; store.len()];    if period == 0 || store.len() <= period {        return supertrend_outputs(values, upper_band, lower_band, trend);    }    for index in period..store.len() {        let atr_value = atr[index]; if atr_value.is_nan() {            continue;        };        let hl2 = (store.high[index] + store.low[index]) / 2.0;        let basic_upper = hl2 + multiplier * atr_value;        let basic_lower = hl2 - multiplier * atr_value;        let previous_close = store.close[index - 1];        let current_upper = if index == period {            basic_upper        } else {            let previous_upper = { let __v = upper_band[index - 1]; if __v.is_nan() { basic_upper } else { __v } };            if basic_upper < previous_upper || previous_close > previous_upper {                basic_upper            } else {                previous_upper            }        };        let current_lower = if index == period {            basic_lower        } else {            let previous_lower = { let __v = lower_band[index - 1]; if __v.is_nan() { basic_lower } else { __v } };            if basic_lower > previous_lower || previous_close < previous_lower {                basic_lower            } else {                previous_lower            }        };        upper_band[index] = current_upper;        lower_band[index] = current_lower;        let current_trend = if index == period {            if store.close[index] >= hl2 {                1.0            } else {                -1.0            }        } else {            let previous_trend = { let __v = trend[index - 1]; if __v.is_nan() { 1.0 } else { __v } };            if previous_trend < 0.0 {                if store.close[index] > current_upper {                    1.0                } else {                    -1.0                }            } else if store.close[index] < current_lower {                -1.0            } else {                1.0            }        };        trend[index] = current_trend;        values[index] = if current_trend < 0.0 { current_upper } else { current_lower };    }    nodes.insert(format!("supertrend:{period}:{multiplier}"), Rc::new(values.clone()));    supertrend_outputs(values, upper_band, lower_band, trend)}
pub fn supertrend_outputs(    values: Series,    upper_band: Series,    lower_band: Series,    trend: Series,) -> Vec<IndicatorOutput> {    vec![        IndicatorOutput {            name: "value".to_string(),            values,        },        IndicatorOutput {            name: "upper_band".to_string(),            values: upper_band,        },        IndicatorOutput {            name: "lower_band".to_string(),            values: lower_band,        },        IndicatorOutput {            name: "trend".to_string(),            values: trend,        },    ]}
pub fn latest_supertrend(    bars: &[Bar],    period: usize,    multiplier: f64,    outputs: &IndicatorArena,) -> (Option<f64>, Option<f64>, Option<f64>, Option<f64>) {    if period == 0 || bars.len() <= period {        return (None, None, None, None);    }    if bars.len() == period + 1 {        let outputs = supertrend(bars, period, multiplier, &mut HashMap::new());        let index = bars.len() - 1;        return (            output_at_vec(&outputs, "value", index),            output_at_vec(&outputs, "upper_band", index),            output_at_vec(&outputs, "lower_band", index),            output_at_vec(&outputs, "trend", index),        );    }    let Some(atr_value) = latest_atr(bars, period, None) else {        return (None, None, None, None);    };    let index = bars.len() - 1;    let hl2 = (bars[index].high + bars[index].low) / 2.0;    let basic_upper = hl2 + multiplier * atr_value;    let basic_lower = hl2 - multiplier * atr_value;    let previous_close = bars[index - 1].close;    let previous_upper = output_at(outputs, "upper_band", index - 1).unwrap_or(basic_upper);    let previous_lower = output_at(outputs, "lower_band", index - 1).unwrap_or(basic_lower);    let previous_trend = output_at(outputs, "trend", index - 1).unwrap_or(1.0);    let upper = if basic_upper < previous_upper || previous_close > previous_upper {        basic_upper    } else {        previous_upper    };    let lower = if basic_lower > previous_lower || previous_close < previous_lower {        basic_lower    } else {        previous_lower    };    let trend = if previous_trend < 0.0 {        if bars[index].close > upper {            1.0        } else {            -1.0        }    } else if bars[index].close < lower {        -1.0    } else {        1.0    };    let value = if trend < 0.0 { upper } else { lower };    (Some(value), Some(upper), Some(lower), Some(trend))}
pub fn latest_supertrend_store(    store: &CandleStore,    period: usize,    multiplier: f64,    outputs: &IndicatorArena,) -> (Option<f64>, Option<f64>, Option<f64>, Option<f64>) {    if period == 0 || store.len() <= period {        return (None, None, None, None);    }    if store.len() == period + 1 {        let outputs = supertrend_store(store, period, multiplier, &mut HashMap::new());        let index = store.len() - 1;        return (            output_at_vec(&outputs, "value", index),            output_at_vec(&outputs, "upper_band", index),            output_at_vec(&outputs, "lower_band", index),            output_at_vec(&outputs, "trend", index),        );    }    let Some(atr_value) = latest_atr_store(store, period, None) else {        return (None, None, None, None);    };    let index = store.len() - 1;    let hl2 = (store.high[index] + store.low[index]) / 2.0;    let basic_upper = hl2 + multiplier * atr_value;    let basic_lower = hl2 - multiplier * atr_value;    let previous_close = store.close[index - 1];    let previous_upper = output_at(outputs, "upper_band", index - 1).unwrap_or(basic_upper);    let previous_lower = output_at(outputs, "lower_band", index - 1).unwrap_or(basic_lower);    let previous_trend = output_at(outputs, "trend", index - 1).unwrap_or(1.0);    let upper = if basic_upper < previous_upper || previous_close > previous_upper {        basic_upper    } else {        previous_upper    };    let lower = if basic_lower > previous_lower || previous_close < previous_lower {        basic_lower    } else {        previous_lower    };    let trend = if previous_trend < 0.0 {        if store.close[index] > upper {            1.0        } else {            -1.0        }    } else if store.close[index] < lower {        -1.0    } else {        1.0    };    let value = if trend < 0.0 { upper } else { lower };    (Some(value), Some(upper), Some(lower), Some(trend))}
